const CLUB_CUSTOMERS = {
      "287196377": { doc: "28.719.637-7", name: "EDNEY NAPOLES", isClub: true },
      "8123311K":  { doc: "8.123.311-K",  name: "SOLEDAD RAMOS",  isClub: true },
      "94031605":  { doc: "94.031.605-5", name: "MARCELA MUÑOZ",  isClub: true }
    };

    let catalog = [{"code": "CV-EUCERIN-001", "emoji": "☀️", "name": "Protector Solar Facial Gel Crema Oil Control FPS 50+ 50ml", "desc": "Venta directa", "listPrice": 23990, "salePrice": 14394, "discountLabel": "-40%", "promoLabel": "", "format": "50 ml", "requiresPrescription": false, "imageDataUrl": "data:image/png;base64,"}, {"code": "CV-ISDIN-001", "emoji": "☀️", "name": "Fotoprotector Fusion Water Magic SPF50", "desc": "Venta directa", "listPrice": 22990, "salePrice": 17242, "discountLabel": "-25%", "promoLabel": "", "format": "Unidad", "requiresPrescription": false, "imageDataUrl": "data:image/png;base64,"}, {"code": "CV-DERCOS-001", "emoji": "🧴", "name": "Shampoo Anti-Caspa Dercos Cabello Graso 390 ml", "desc": "Venta directa", "listPrice": 24990, "salePrice": 18742, "discountLabel": "-25%", "promoLabel": "", "format": "390 ml", "requiresPrescription": false, "imageDataUrl": "data:image/png;base64,"}, {"code": "CV-BIODERMA-001", "emoji": "🧴", "name": "Sensibio H2O agua micelar para Piel sensible 500ml", "desc": "Venta directa", "listPrice": 27990, "salePrice": 16794, "discountLabel": "-40%", "promoLabel": "", "format": "500 ml", "requiresPrescription": false, "imageDataUrl": "data:image/png;base64,"}, {"code": "CV-VICHY-001", "emoji": "💧", "name": "Liftactiv Supreme Serum Vitamina C 20 ml", "desc": "Venta directa", "listPrice": 41990, "salePrice": 25194, "discountLabel": "-40%", "promoLabel": "", "format": "20 ml", "requiresPrescription": false, "imageDataUrl": "data:image/png;base64,"}, {"code": "CV-OZEMPIC-001", "emoji": "💉", "name": "Ozempic 0,25mg/0,5mg Semaglutida 2 mg / 1,5 mL Solución inyectable 1 Dispositivo Prellenado + 6 Agujas Desechables", "desc": "Receta", "listPrice": 219930, "salePrice": 197937, "discountLabel": "-10%", "promoLabel": "2ª un 50% · 1ª un 10%", "format": "2 mg / 1,5 mL", "requiresPrescription": true, "imageDataUrl": "data:image/png;base64,"}, {"code": "CV-PAMPERS-001", "emoji": "🍼", "name": "Pañales Premium Care Pants Talla XXG, 104 Unidades", "desc": "Venta directa", "listPrice": 47990, "salePrice": 33593, "discountLabel": "-30%", "promoLabel": "", "format": "104 unidades", "requiresPrescription": false, "imageDataUrl": "data:image/png;base64,"}];
    let cart = [];
    let currentProduct = null;
    let customer = {doc:'', name:'', isClub:false, lookedUp:false};
    let selectedMethod = 'qr';
    let selectedSubOption = 'redcompra';
    let orderCounter = 1001;

    let stream = null, detector = null, autoScanOn = false, scanLoopHandle = null, toastTimer = null;

    const $ = (id) => document.getElementById(id);
    const money = n => new Intl.NumberFormat('es-CL', {style:'currency', currency:'CLP', maximumFractionDigits:0}).format(Number(n||0));

    function toast(msg) {
      const t = $('toast');
      t.textContent = msg;
      t.classList.add('show');
      clearTimeout(toastTimer);
      toastTimer = setTimeout(() => t.classList.remove('show'), 2300);
    }

    function go(id) {
      document.querySelectorAll('.screen').forEach(s => s.classList.remove('active'));
      const target = $(id);
      if (target) target.classList.add('active');
      if (id === 'scan') renderCatalogCards();
      if (id === 'cart') renderCart();
      if (id === 'payment') $('paymentTotal').textContent = money(totalSale());
      if (id === 'qrpay') $('orderRef').textContent = orderCounter;
      if (id === 'catalog') renderCatalogAdmin();
      syncCustomerUi();
      window.scrollTo({top:0, behavior:'smooth'});
    }

    function escapeHtml(s) {
      return String(s ?? "").replace(/[&<>"']/g, (m)=>({
        "&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;"
      })[m]);
    }

    function rutClean(input) { return String(input||'').toUpperCase().replace(/[^0-9K]/g,''); }
    function rutFormat(clean) {
      if(!clean) return '';
      if(clean.length === 1) return clean;
      const dv = clean.slice(-1);
      let body = clean.slice(0,-1).replace(/^0+/, '') || '0';
      return body.replace(/\B(?=(\d{3})+(?!\d))/g, '.') + '-' + dv;
    }
    function rutBodyNumber(clean) {
      if(!clean || clean.length < 2) return null;
      const body = clean.slice(0,-1);
      if(!/^\d+$/.test(body)) return null;
      return Number(body);
    }

    document.addEventListener('input', (ev) => {
      if(ev.target && ev.target.id === 'customerDoc') {
        const clean = rutClean(ev.target.value);
        ev.target.value = rutFormat(clean);
      }
    });

    function lookupCustomer() {
      const clean = rutClean($('customerDoc').value);
      if(clean.length < 2) return toast('Ingresa un RUT válido');
      const bodyNum = rutBodyNumber(clean);
      if(bodyNum === null) return toast('RUT inválido');
      if(bodyNum >= 50000000) return toast('RUT fuera de rango persona natural');
      const formatted = rutFormat(clean);
      const found = CLUB_CUSTOMERS[clean];
      if(found) {
        customer = { doc: found.doc || formatted, name: found.name, isClub: true, lookedUp: true };
        toast('Cliente Club encontrado');
      } else {
        customer = { doc: formatted, name: formatted, isClub: false, lookedUp: true };
        toast('Cliente no es parte del Club');
      }
      syncCustomerUi();
      go('cart');
    }

    function clearCustomer() {
      customer = {doc:'', name:'', isClub:false, lookedUp:false};
      $('customerDoc').value = '';
      syncCustomerUi();
      toast('Cliente limpiado');
    }

    function syncCustomerUi() {
      const showClub = !!(customer.lookedUp && customer.isClub);
      const showNonClub = !!(customer.lookedUp && !customer.isClub);

      $('scanClubBanner').classList.toggle('hidden', !showClub);
      $('scanNonClubBanner').classList.toggle('hidden', !showNonClub);
      $('clubCustomerNameScan').textContent = customer.name || 'Cliente Club';
      $('nonClubCustomerNameScan').textContent = customer.doc ? `Cliente ${customer.doc}` : 'Cliente';

      $('cartClubBanner').classList.toggle('hidden', !showClub);
      $('cartNonClubBanner').classList.toggle('hidden', !showNonClub);
      $('clubCustomerNameCart').textContent = customer.name || 'Cliente Club';
      $('nonClubCustomerNameCart').textContent = customer.doc ? `Cliente ${customer.doc}` : 'Cliente';

      $('clubBanner').classList.toggle('hidden', !showClub);
      $('nonClubBanner').classList.toggle('hidden', !showNonClub);
      $('clubCustomerName').textContent = customer.name || 'Cliente Club';
      $('nonClubCustomerName').textContent = customer.doc ? `Cliente ${customer.doc}` : 'Cliente';

      $('cartCustomerHint').textContent = !customer.lookedUp
        ? 'No ingresado'
        : (customer.isClub ? `Club: ${customer.name}` : `No Club: ${customer.doc}`);
    }

    function renderCatalogCards() {
      $('demoList').innerHTML = catalog.map((p,i) => `
        <div class="product-demo">
          <div class="thumb">${p.imageDataUrl ? `<img alt="${escapeHtml(p.name)}" src="${p.imageDataUrl}">` : (p.emoji || '🛒')}</div>
          <div>
            <h3>${escapeHtml(p.name)}</h3>
            <p class="muted tiny">${escapeHtml(p.desc)}</p>
            <div class="row" style="gap:8px;flex-wrap:wrap">
              <span class="badge badge-info">Lista ${money(p.listPrice)}</span>
              <span class="badge badge-ok">Oferta ${money(p.salePrice)}</span>
              <span class="badge sale-flag">${p.discountLabel}</span>
              ${p.requiresPrescription ? '<span class="badge badge-danger">Receta</span>' : '<span class="badge badge-ok">Venta directa</span>'}
            </div>
            ${p.promoLabel ? `<div class="tiny" style="margin-top:6px;color:#7c2d12;font-weight:700">${escapeHtml(p.promoLabel)}</div>` : ''}
          </div>
          <button class="btn btn-primary btn-small" type="button" onclick="openProductByIndex(${i})">Escanear</button>
        </div>
      `).join('');
    }

    function openProductByIndex(i) {
      const p = catalog[i];
      if(!p) return toast('Producto no encontrado');
      currentProduct = p;
      $('productHero').innerHTML = p.imageDataUrl
        ? `<img alt="${escapeHtml(p.name)}" src="${p.imageDataUrl}">`
        : `<div style="font-size:72px">${p.emoji || '🛒'}</div>`;
      $('productName').textContent = p.name;
      $('productDesc').textContent = p.desc;
      $('productListPrice').textContent = money(p.listPrice);
      $('productSalePrice').textContent = money(p.salePrice);
      $('productDiscount').textContent = p.discountLabel || '-';
      $('productCode').textContent = p.code;
      $('productFormat').textContent = p.format || 'Unidad';
      const promo = $('productPromo');
      if (p.promoLabel) {
        promo.textContent = p.promoLabel;
        promo.classList.remove('hidden');
      } else {
        promo.textContent = '';
        promo.classList.add('hidden');
      }
      go('product');
    }

    function totalList() {
      return cart.reduce((acc, item) => acc + item.listPrice * (item.qty || 1), 0);
    }
    function totalSale() {
      return cart.reduce((acc, item) => acc + calcLineSale(item), 0);
    }
    function totalDiscount() {
      return totalList() - totalSale();
    }

    function calcLineSale(item) {
      if(item.code === 'CV-OZEMPIC-001' && item.qty >= 2) {
        const pairs = Math.floor(item.qty / 2);
        const remainder = item.qty % 2;
        const first = item.listPrice * 0.90;   // 10% off
        const second = item.listPrice * 0.50;  // 50% off
        return Math.round(pairs * (first + second) + remainder * first);
      }
      return Math.round(item.salePrice * (item.qty || 1));
    }

    function addCurrentProduct() {
      if(!currentProduct) return toast('No hay producto seleccionado');
      const existing = cart.find(x => x.code === currentProduct.code);
      if(existing) existing.qty += 1;
      else cart.push({...currentProduct, qty:1});
      toast('Producto agregado al carrito');
      go('cart');
    }

    function removeItem(idx) {
      cart.splice(idx,1);
      renderCart();
      toast('Producto eliminado');
    }

    function changeQty(idx, delta) {
      const item = cart[idx];
      if(!item) return;
      item.qty = Math.max(1, (item.qty || 1) + delta);
      renderCart();
    }

    function renderCart() {
      const wrap = $('cartList');
      if(!cart.length) {
        wrap.innerHTML = '<p class="muted">Aún no hay productos en la orden. Vuelve a escanear.</p>';
      } else {
        wrap.innerHTML = cart.map((p,idx) => `
          <div class="cart-item">
            <div class="avatar">${p.imageDataUrl ? `<img alt="${escapeHtml(p.name)}" src="${p.imageDataUrl}">` : (p.emoji || '🛒')}</div>
            <div>
              <strong>${escapeHtml(p.name)}</strong>
              <div class="tiny muted">${escapeHtml(p.code)} · ${escapeHtml(p.format || 'Unidad')} · Cant: ${p.qty}</div>
              <div class="tiny" style="margin-top:4px">
                <span class="badge badge-info">Lista ${money(p.listPrice)}</span>
                <span class="badge badge-ok">Línea ${money(calcLineSale(p))}</span>
                ${p.promoLabel ? `<span class="badge badge-warn">${escapeHtml(p.promoLabel)}</span>` : ''}
              </div>
              <div class="row" style="margin-top:8px">
                <button class="btn btn-secondary btn-small" type="button" onclick="changeQty(${idx},-1)">-</button>
                <button class="btn btn-secondary btn-small" type="button" onclick="changeQty(${idx},1)">+</button>
                <button class="btn btn-ghost btn-small" type="button" onclick="removeItem(${idx})">Quitar</button>
              </div>
            </div>
            <div style="text-align:right"><strong>${money(calcLineSale(p))}</strong></div>
          </div>
        `).join('');
      }
      $('subtotal').textContent = money(totalList());
      $('discount').textContent = money(totalDiscount());
      $('total').textContent = money(totalSale());
      syncCustomerUi();
    }

    function renderCatalogAdmin() {
      $('catCount').textContent = `${catalog.length} items`;
      $('catalogList').innerHTML = catalog.map((p) => `
        <div class="product-demo">
          <div class="thumb">${p.imageDataUrl ? `<img alt="${escapeHtml(p.name)}" src="${p.imageDataUrl}">` : (p.emoji || '🛒')}</div>
          <div>
            <h3>${escapeHtml(p.name)}</h3>
            <p class="muted tiny">${escapeHtml(p.desc)}</p>
            <div class="tiny muted">Código: <b>${escapeHtml(p.code)}</b> · Formato: ${escapeHtml(p.format || '-')}</div>
            <div class="row" style="gap:8px;flex-wrap:wrap;margin-top:6px">
              <span class="badge badge-info">Lista ${money(p.listPrice)}</span>
              <span class="badge badge-ok">Oferta ${money(p.salePrice)}</span>
              <span class="badge sale-flag">${p.discountLabel}</span>
            </div>
          </div>
          <button class="btn btn-primary btn-small" type="button" onclick="openProductByCode('${escapeHtml(p.code)}')">Ver</button>
        </div>
      `).join('');
    }

    function openProductByCode(code) {
      const i = catalog.findIndex(x => x.code === code);
      if(i >= 0) openProductByIndex(i);
    }

    function updateBarcodeSupportBadge() {
      const badge = $('barcodeSupport');
      if('BarcodeDetector' in window) {
        badge.textContent = 'Auto-escaneo soportado';
        badge.className = 'badge badge-ok';
      } else {
        badge.textContent = 'Auto-escaneo NO soportado';
        badge.className = 'badge badge-warn';
      }
    }

    async function startCamera() {
      if(!navigator.mediaDevices?.getUserMedia) return toast('Este navegador no permite cámara en este contexto.');
      try {
        stream = await navigator.mediaDevices.getUserMedia({video:{facingMode:'environment'}, audio:false});
        $('video').srcObject = stream;
        $('video').classList.remove('hidden');
        $('videoFallback').classList.add('hidden');
        toast('Cámara activada');
      } catch(err) {
        toast('No se pudo activar la cámara. Usa el catálogo o ingreso manual.');
      }
    }

    function stopCamera() {
      if(stream) {
        stream.getTracks().forEach(t => t.stop());
        stream = null;
      }
      $('video').srcObject = null;
      $('video').classList.add('hidden');
      $('videoFallback').classList.remove('hidden');
    }

    function scanByCode() {
      const code = $('manualCode').value.trim();
      if(!code) return toast('Ingresa un código');
      const p = catalog.find(x => String(x.code).trim() === code);
      if(!p) return toast('Código no encontrado en catálogo');
      openProductByCode(code);
    }

    function toggleAutoScan() {
      if(autoScanOn) return stopAutoScan();
      startAutoScan();
    }

    function startAutoScan() {
      if(!('BarcodeDetector' in window)) return toast('Auto-escaneo no soportado. Usa ingreso manual.');
      if(!stream) return toast('Primero activa la cámara');
      detector = new BarcodeDetector({ formats: ['ean_13','ean_8','upc_a','upc_e','code_128','code_39','code_93','qr_code'] });
      autoScanOn = true;
      $('autoScanLabel').textContent = 'Detener auto-escaneo';
      toast('Auto-escaneo iniciado');
      scanLoop();
    }

    function stopAutoScan() {
      autoScanOn = false;
      $('autoScanLabel').textContent = 'Iniciar auto-escaneo';
      if(scanLoopHandle) cancelAnimationFrame(scanLoopHandle);
      scanLoopHandle = null;
      detector = null;
    }

    async function scanLoop() {
      if(!autoScanOn || !detector) return;
      const video = $('video');
      if(video.readyState >= 2) {
        try {
          const codes = await detector.detect(video);
          if(codes && codes.length) {
            const raw = (codes[0].rawValue || '').trim();
            if(raw) {
              stopAutoScan();
              $('manualCode').value = raw;
              toast('Código detectado: ' + raw);
              const p = catalog.find(x => String(x.code).trim() === raw);
              if(p) openProductByCode(raw);
              else toast('Código no existe en catálogo.');
              return;
            }
          }
        } catch(e) {}
      }
      scanLoopHandle = requestAnimationFrame(scanLoop);
    }

    function selectMethodCard(el) {
      document.querySelectorAll('.pay-option').forEach(x => x.classList.remove('active'));
      el.classList.add('active');
      selectedMethod = el.dataset.method;
    }

    function selectSubOption(el) {
      document.querySelectorAll('#webpaySuboptions .subopt').forEach(x => x.classList.remove('active'));
      el.classList.add('active');
      selectedSubOption = el.dataset.sub;
    }

    function setProcessingVisible(visible) {
      $('processingBox').classList.toggle('hidden', !visible);
    }

    function continuePayment() {
      if(!cart.length) return toast('Agrega productos al carrito');
      if(selectedMethod === 'qr') return go('qrpay');

      const badge = $('walletMethodBadge');
      const title = $('walletTitle');
      const desc = $('walletDesc');
      const sub = $('webpaySuboptions');
      setProcessingVisible(false);
      badge.textContent = selectedMethod;

      if(selectedMethod === 'webpay') {
        title.textContent = 'Webpay (Transbank)';
        desc.textContent = 'Selecciona el tipo de pago (Débito o Crédito) y autoriza.';
        sub.classList.remove('hidden');
        selectedSubOption = 'redcompra';
        sub.querySelectorAll('.subopt').forEach((x,idx)=>x.classList.toggle('active', idx===0));
      } else if(selectedMethod === 'gpay') {
        title.textContent = 'Google Pay';
        desc.textContent = 'Simulación de tokenización y autorización rápida en Android.';
        sub.classList.add('hidden');
      } else {
        title.textContent = 'Mercado Pago';
        desc.textContent = 'Simulación de wallet / checkout con confirmación por callback.';
        sub.classList.add('hidden');
      }
      go('walletpay');
    }

    function simulateApproval(msg='Pago aprobado correctamente') {
      $('successMessage').textContent = msg;
      $('successOrder').textContent = orderCounter;
      $('successTotal').textContent = money(totalSale());
      $('successCustomer').textContent = customer.lookedUp ? (customer.name || customer.doc) : 'Invitado';
      go('success');
    }

    function simulateProcessingAndApprove(customMsg) {
      setProcessingVisible(true);
      let payLabel = '';
      if(selectedMethod === 'webpay') {
        payLabel = selectedSubOption === 'redcompra' ? 'Redcompra (Débito)' :
                   selectedSubOption === 'visa' ? 'Crédito Visa' : 'Crédito MasterCard';
      } else if(selectedMethod === 'gpay') {
        payLabel = 'Google Pay';
      } else {
        payLabel = 'Mercado Pago';
      }
      $('processingTitle').textContent = 'Procesando pago…';
      $('processingSubtitle').textContent = `Autorizando con ${payLabel}`;
      const delay = 1400 + Math.floor(Math.random()*900);
      setTimeout(() => {
        setProcessingVisible(false);
        simulateApproval(customMsg || `Pago aprobado (${payLabel})`);
      }, delay);
    }

    function simulateProcessingAndFail() {
      setProcessingVisible(true);
      $('processingTitle').textContent = 'Procesando pago…';
      $('processingSubtitle').textContent = 'Validando autorización';
      const delay = 1200 + Math.floor(Math.random()*800);
      setTimeout(() => {
        setProcessingVisible(false);
        toast('Pago rechazado (demo)');
      }, delay);
    }

    function newOrder() {
      cart = [];
      selectedMethod = 'qr';
      selectedSubOption = 'redcompra';
      orderCounter++;
      $('manualCode').value = '';
      document.querySelectorAll('.pay-option').forEach((x,idx)=>x.classList.toggle('active', idx===0));
      stopAutoScan();
      stopCamera();
      clearCustomer();
      go('home');
      toast('Nueva compra iniciada');
    }

    function bindEvents() {
      document.querySelectorAll('[data-go]').forEach(btn => btn.addEventListener('click', () => go(btn.dataset.go)));
      $('cameraBtn').addEventListener('click', startCamera);
      $('autoScanBtn').addEventListener('click', toggleAutoScan);
      $('manualSearchBtn').addEventListener('click', scanByCode);
      $('lookupCustomerBtn').addEventListener('click', lookupCustomer);
      $('clearCustomerBtn').addEventListener('click', clearCustomer);
      $('addProductBtn').addEventListener('click', addCurrentProduct);
      $('continuePaymentBtn').addEventListener('click', continuePayment);
      $('approveQrBtn').addEventListener('click', () => simulateProcessingAndApprove('Pago QR confirmado en POS'));
      $('approveWalletBtn').addEventListener('click', () => simulateProcessingAndApprove());
      $('failPayBtn').addEventListener('click', simulateProcessingAndFail);
      $('newOrderBtn').addEventListener('click', newOrder);
      document.querySelectorAll('.pay-option').forEach(el => el.addEventListener('click', () => selectMethodCard(el)));
      document.querySelectorAll('#webpaySuboptions .subopt').forEach(el => el.addEventListener('click', () => selectSubOption(el)));
    }

    function init() {
      bindEvents();
      updateBarcodeSupportBadge();
      renderCatalogCards();
      renderCatalogAdmin();
      syncCustomerUi();
    }
    init();
